// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/token/ERC20/ERC20.sol";

contract BelongToken is ERC20, Ownable, ReentrancyGuard {
    bytes32 public constant BURNER_ROLE = keccak256("BURNER_ROLE");

    constructor(uint256 initialSupply) ERC20("Belong Token", "BLG") {
        _mint(msg.sender, initialSupply);
        _setupRole(BURNER_ROLE, msg.sender);
    }

    function burn(uint256 amount) public nonReentrant {
        require(hasRole(BURNER_ROLE, msg.sender) || msg.sender == owner(), "Caller is not the burner or owner");
        _burn(msg.sender, amount);
    }

    // Additional functions and modifiers can be added here
}
