// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "forge-std/Test.sol";
import "./BelongToken.sol";

contract BelongTokenTest is Test {
    BelongToken token;
    address owner;
    address burner;
    address user;

    function setUp() public {
        owner = address(this);
        burner = address(0x123);
        user = address(0x456);

        token = new BelongToken(1000000 * 10**18); // 1 million tokens

        token.grantRole(token.BURNER_ROLE(), burner);
    }

    function testBurnByOwner() public {
        token.burn(100000 * 10**18);
        assertEq(token.balanceOf(owner), 900000 * 10**18);
    }

    function testBurnByBurner() public {
        vm.prank(burner);
        token.burn(100000 * 10**18);
        assertEq(token.balanceOf(burner), 900000 * 10**18);
    }

    function testBurnByUserReverts() public {
        vm.expectRevert("Caller is not the burner or owner");
        vm.prank(user);
        token.burn(100000 * 10**18);
    }

    function testReentrancyGuard() public {
        vm.expectRevert("ReentrancyGuard: reentrant call");
        vm.prank(user);
        token.burn(100000 * 10**18);
        token.burn(100000 * 10**18);
    }
}
